        if len(pair) != 2:
            raise ValidationError(f'Invalid group: {group}')

        k, v = pair

        k = k.strip()
        v = v.strip()

        if not k or not v:
            raise ValidationError(f'Invalid group: {group}')

        # Account for 'list' support
        if v.startswith('[') and v.endswith(']'):
            try:
                v = json.loads(v)
            except json.JSONDecodeError:
                raise ValidationError(f'Invalid list value: {v}')

